// Parse:  /render <pillar> [hook="..."] [variant=N] [account=severus] [source=seedance|user_upload|hybrid]
// Or:     /assemble <pillar> [hook="..."] [variant=N] [account=severus]
const raw = $input.first().json.message.text || '';
const match = raw.match(/^\/(render|assemble)\s+(\S+)(.*)$/);
if (!match) {
  return [{ json: { error: 'Could not parse command', raw } }];
}
const command = match[1];
const pillar = match[2];
const rest = match[3] || '';

// Pull key="value with spaces" or key=value
const params = {};
const kvRegex = /(\w+)=("([^"]+)"|(\S+))/g;
let m;
while ((m = kvRegex.exec(rest)) !== null) {
  params[m[1].toLowerCase()] = m[3] !== undefined ? m[3] : m[4];
}

const account = params.account || 'severus';
const variantIndex = params.variant !== undefined ? parseInt(params.variant, 10) : null;
const hookOverride = params.hook || null;
const assetSource = params.source || (command === 'assemble' ? 'user_upload' : null);

return [{
  json: {
    command,
    pillar,
    account,
    variantIndex,
    hookOverride,
    assetSource,
    chat_id: $input.first().json.message.chat.id,
    message_id: $input.first().json.message.message_id,
    from_username: $input.first().json.message.from?.username || 'unknown',
  },
}];
